@module swingEditor  src=swingEditor.lua  loc=674  sha=0067830  mode=chunk
@deps tv, cm, chrome, ctx, facade

# Invariants & contracts
  @invariant  editor owns no swing data; composite resolves via cm:get('swings', {mergeTiers=true})[name] (defaults ∪ global ∪ project) and is read fresh each frame via swingRead
  @invariant  all writes route through swingWrite (idempotent → tv:setSwingComposite); commit() drives cross-take reswing on widget release
  @invariant  state == nil iff editor is closed; open() is a no-op when already open; Esc / close-button clears state
  @invariant  snapshot is captured at open() (and on swing-switch via the library picker) and never mutated; Reset writes a deepClone of it
  @invariant  shift is in QN and atom-independent — preserved across atom swap, only re-clamped to the new atom's cap
  @invariant  on period change shift scales by newPeriod/oldPeriod, holding resolved s = shift/tileQN (and thus slope) constant; then re-clamped
  @invariant  slider lo/hi = T_tile · {-negRange, +posRange} (asymmetric for shuffle/tilt); Wild unlocks hard, otherwise clamped to ±SWING_SOFT_QN; hi <= 0 freezes the slider
  @invariant  atom-combo speaks tile-QN (user-period × pulsesPerCycle); writes divide back via periodOverPPC so storage stays user-period
  @contract  no-op when already open. Default selection prefers the cursor

# Shapes
  @shape  state = { name, snapshot, rpb, wild, create? = { buf, err?, gen?, refocus? } }  -- composite is NOT cached here; create is the New-swing modal substate (gen bumps to re-seed the InputText after we clear buf on error)
  @shape  PeriodPreset = { label = string, period = number|{num,den} }  -- period in user-facing QN

# Imports
  @require util = 'util'  @ 14
  @require timing = 'timing'  @ 15
  @require ImGui = 'imgui'  @ 21

# Private state
  @state SWING_ATOMS = { 'id',  @ 23
  @state SWING_ATOMS_Z = table.concat(SWING_ATOMS, '\0') .. '\0\0'  @ 25
  @state RPB_CHOICES = { 1, 2, 3, 4, 6, 8, 12, 16 }  @ 27
  @state PERIOD_PRESETS = {  @ 31
  @state SWING_ERR = 0xff6060ff  @ 40
  @state SWING_MARK = 0x000000b0  @ 41
  @state SWING_SOFT_QN = 0.15  @ 42
  @state state = nil  @ 48
  @state self = {}  @ 647

# Private functions
  @fn arrange()  @ 46
  @fn commit()  @ 51
      -- Fired on widget release so the project-wide pass runs once per gesture, not per frame.
  @fn meterQN()  @ 55
  @fn periodPresetIndex(tileQN)  @ 62
      @contract  returns 0 (not nil) when tileQN matches no preset; callers append a synthetic label in that case
  @fn periodLabel(tileQN)  @ 69
  @fn periodOverPPC(period, ppC)  @ 77
      -- Preset .period is already a tidy rational; halving it for ppC=2 keeps
      -- it tidy ({n,d} → {n,2d}; integer → {n,2}).
  @fn shiftCap(factor, wild)  @ 87
      -- id has range = ∞ (slope is always 1; the K-bound never bites). Cap at
      -- one tile per side so Wild gives a finite slider; the boundary clip
      -- absorbs any overhang at the take edges. shuffle and tilt are
      -- asymmetric (positive and negative shifts hit different K-bound walls).
  @fn materialise(composite)  @ 102
      -- QN-space preview uses ppqPerQN=1 so the editor draws against
      -- normalised QN units rather than the take's PPQ resolution.
  @fn drawSwingGrid(composite, periodQN, rpb, w, h, shadeMeter)  @ 104
  @fn swingRead()  @ 173
  @fn readFactors(composite)  @ 179
      -- Tolerant accessor: bare {} and {factors={}} both mean identity. Read-only;
      -- write paths deepClone, then mutate factors[].
  @fn phaseQN(p)  @ 184
      -- QN value of an optional period-shaped slot (scalar, {n,d}, or nil).
  @fn compositesEqual(a, b)  @ 187
      @contract  compares composite phase, per-factor phase, period, atom and shift — phase fields normalise to QN before comparing, so {1,2} and {2,4} count equal
  @fn swingWrite(composite)  @ 204
      @contract  sole write path; idempotent on equal composites; the active-take refresh happens via tv:setSwingComposite's configChanged broadcast (granular per-channel stale-mark + tm:rebuild)
  @fn cloneForEdit()  @ 211
      -- Editable clone with a guaranteed factors[] array, so write paths can
      -- index it without re-checking. Phase is preserved as-is.
  @fn patchFactor(i, patch)  @ 217
  @fn addFactor()  @ 225
      @contract  default new factor is identity (atom='id', shift=0, period=1) — visually inert until edited
  @fn removeFactor(i)  @ 231
  @fn moveFactor(i, dir)  @ 237
  @fn drawFactorRow(i, f, availW)  @ 247
  -- Tier-aware library writes
  @fn projectSwings()  @ 349
  @fn globalSwings()  @ 350
  @fn saveGlobal(name)  @ 353
      @contract  copies the currently-edited composite into the global tier (defaults are immutable; project copy survives untouched, still shadowing it)
  @fn deleteFromTier(level, name)  @ 360
  @fn switchTo(name)  @ 369
      -- Switch the edited swing without closing the editor. Re-captures the
      -- snapshot so Reset/dirty-check stay coherent.
  @fn resolvedSlots()  @ 378
      -- Resolved take and channel slots for the open-default and the
      -- library-row shortcut buttons. 'identity' at the take tier is treated
      -- as no-slot (matches open()'s bail); at the channel tier nil means
      -- 'no override, fall through to take'.
  @fn drawLibraryRow(closeOnClick, rowW)  @ 390
      -- Library row sits above the edit/create body. Picker + name input flow
      -- coexist: the picker offers existing swings (including the implicit
      -- "Off" → enter create mode); +New is just an alias for picking Off and
      -- focusing the name field.
  @fn drawCreateModal()  @ 469
      -- '+ New' modal. Lives at draw() top-level so the popup isn't bound to a
      -- child window's lifetime; the editor body greys out behind it via the
      -- disabled wrap in drawEditBody.
  @fn drawEditBody(composite, n)  @ 524
  @fn draw(w, h)  @ 617
      -- Body-region draw. Caller (trackerPage) hands us its body rect via
      -- renderBody; we run inside a child window so the chrome palette
      -- (editor.bg + toolbar button/text colours + separator tint) takes
      -- the place of the tracker grid's background. Mirrors the styling
      -- that pushChromeWindow gave the editor in its old floating-window
      -- form, swapping Col_WindowBg for Col_ChildBg.

# Public API (self:*)
  -- Public
  @api self:open()  @ 654
      --           channel's swing override, falls back to the take's swing, and
      --           is nil when neither resolves (body greys out; user can '+' or
      --           use the Take/Chan shortcut buttons). snapshot is the current cm
      --           composite at open time, used for Reset and dirty-check.
  @api self:render(w, h)  @ 666
  @api self:close()  @ 668
  @api self:isOpen()  @ 670
  @api self:modalActive()  @ 671

